from abc import ABC, abstractmethod
class Notifier(ABC):
    @abstractmethod
    def send(self, msg): pass
class EmailNotifier(Notifier):
    def send(self, msg): return f'Email: {msg}'
class SMSNotifier(Notifier):
    def send(self, msg): return f'SMS: {msg}'

